import React, { useEffect } from 'react';
import { db } from '../firebase';
import { doc, updateDoc, increment } from 'firebase/firestore';
import { ArrowLeft, ExternalLink, Calendar, User, Tag, Eye, LayoutGrid, Image as ImageIcon } from 'lucide-react';

function ProjectDetails({ project, onBack }) {
  
  // 📈 Automatically increment views when the page loads
  useEffect(() => {
    if (project && project.id) {
      const incrementView = async () => {
        try {
          const projectRef = doc(db, 'projects', project.id);
          await updateDoc(projectRef, { views: increment(1) });
        } catch (err) {
          console.error("Failed to update views", err);
        }
      };
      incrementView();
    }
  }, [project]);

  if (!project) return null;

  // 🚨 THE FIX: Checking BOTH old database formats and new database formats!
  const liveLink = project.liveDemoUrl || project.link;
  const authorDisplay = project.authorName || project.author || 'NIMIT Student';
  
  // Format the date safely
  let dateDisplay = 'Recent Submission';
  if (project.createdAt && project.createdAt.toDate) {
    dateDisplay = new Date(project.createdAt.toDate()).toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
  }

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-100 font-sans pb-12 selection:bg-indigo-500/30">
      
      {/* 🎨 Header Navigation */}
      <div className="bg-black/50 backdrop-blur-xl border-b border-white/10 sticky top-0 z-40">
        <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
          <button onClick={onBack} className="flex items-center gap-2 px-4 py-2 rounded-full hover:bg-white/10 transition-colors text-gray-400 hover:text-white font-semibold text-sm border border-transparent hover:border-white/10">
            <ArrowLeft className="w-5 h-5" /> Back to Repository
          </button>
          
          <div className="flex items-center gap-2 bg-indigo-500/10 border border-indigo-500/20 px-4 py-1.5 rounded-full">
            <ShieldCheckIcon className="w-4 h-4 text-indigo-400" />
            <span className="text-xs font-bold text-indigo-300 tracking-wider uppercase">Verified Project</span>
          </div>
        </div>
      </div>

      <div className="max-w-6xl mx-auto px-6 mt-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          
          {/* ⬅️ LEFT COLUMN: Main Visuals & Description */}
          <div className="lg:col-span-2 space-y-6">
            
            {/* Main Cover Image */}
            <div className="w-full h-[400px] bg-white/5 border border-white/10 rounded-[2rem] overflow-hidden relative shadow-[0_0_40px_rgba(0,0,0,0.3)] flex items-center justify-center">
              {project.imageUrl ? (
                <img src={project.imageUrl} alt={project.title} className="w-full h-full object-cover" />
              ) : (
                <div className="flex flex-col items-center text-gray-600 gap-3">
                  <ImageIcon className="w-16 h-16" />
                  <span className="text-sm font-medium">No cover image provided</span>
                </div>
              )}
            </div>

            {/* Description Card */}
            <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8 backdrop-blur-md">
              <h2 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                <LayoutGrid className="w-5 h-5 text-indigo-400" /> Executive Summary
              </h2>
              <p className="text-gray-300 leading-relaxed whitespace-pre-wrap text-lg">
                {project.description}
              </p>
            </div>
          </div>

          {/* ➡️ RIGHT COLUMN: Sidebar Details & Action Buttons */}
          <div className="space-y-6">
            
            <div className="bg-white/5 border border-white/10 rounded-[2rem] p-8 backdrop-blur-md flex flex-col items-start shadow-xl relative overflow-hidden">
              {/* Glow */}
              <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/20 blur-[50px] rounded-full pointer-events-none"></div>

              <span className="bg-indigo-500/20 text-indigo-300 border border-indigo-500/30 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider mb-4 relative z-10">
                {project.category || 'App'}
              </span>
              
              <h1 className="text-4xl font-extrabold text-white mb-6 relative z-10 leading-tight">
                {project.title}
              </h1>

              {/* 🚀 THE LIVE LINK BUTTON */}
              {liveLink ? (
                <a href={liveLink} target="_blank" rel="noopener noreferrer" className="w-full bg-white text-black py-4 rounded-xl font-bold text-lg flex justify-center items-center gap-2 hover:bg-gray-200 transition-all hover:scale-[1.02] shadow-[0_0_30px_rgba(255,255,255,0.2)] mb-8 relative z-10">
                  Launch App <ExternalLink className="w-5 h-5" />
                </a>
              ) : (
                <div className="w-full bg-white/5 border border-white/10 py-4 rounded-xl font-bold text-sm text-gray-500 flex justify-center items-center mb-8 cursor-not-allowed">
                  No Live Demo Available
                </div>
              )}

              {/* Meta Data Box */}
              <div className="w-full space-y-3 relative z-10">
                <div className="flex items-center gap-4 bg-black/40 border border-white/5 p-4 rounded-xl">
                  <div className="w-10 h-10 bg-indigo-500/20 rounded-full flex items-center justify-center border border-indigo-500/30">
                    <User className="w-5 h-5 text-indigo-400" />
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-wider">Developer</p>
                    <p className="text-sm font-semibold text-white">{authorDisplay}</p>
                  </div>
                </div>

                <div className="flex items-center gap-4 bg-black/40 border border-white/5 p-4 rounded-xl">
                  <div className="w-10 h-10 bg-purple-500/20 rounded-full flex items-center justify-center border border-purple-500/30">
                    <Calendar className="w-5 h-5 text-purple-400" />
                  </div>
                  <div>
                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-wider">Submission Date</p>
                    <p className="text-sm font-semibold text-white">{dateDisplay}</p>
                  </div>
                </div>
              </div>

              <div className="w-full mt-6 pt-6 border-t border-white/10 flex justify-between items-center text-xs text-gray-500 font-mono">
                <span>ID: {project.id.slice(0, 8).toUpperCase()}</span>
                <span className="flex items-center gap-1"><Eye className="w-3 h-3" /> {project.views || 0}</span>
              </div>
            </div>
            
          </div>

        </div>
      </div>
    </div>
  );
}

// Custom mini component for the verified badge icon
const ShieldCheckIcon = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10" />
    <path d="m9 12 2 2 4-4" />
  </svg>
);

export default ProjectDetails;
